const FLASH=[{"id": "ethics-f01", "sec": "ethics", "front": "Independence", "back": "A direct financial interest by a covered member impairs independence regardless of materiality. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}, {"id": "ethics-f02", "sec": "ethics", "front": "Objectivity", "back": "Objectivity requires fair evaluation of evidence and misstatements, including qualitative factors. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}, {"id": "ethics-f03", "sec": "ethics", "front": "Due professional care", "back": "Due care includes appropriate planning, supervision, review, and professional skepticism. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}, {"id": "ethics-f04", "sec": "ethics", "front": "Professional skepticism", "back": "Skepticism requires a questioning mind and critical assessment of contradictory evidence. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}, {"id": "ethics-f05", "sec": "ethics", "front": "Engagement acceptance", "back": "Acceptance procedures include independence, competence, management integrity, and engagement risk. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}, {"id": "ethics-f06", "sec": "ethics", "front": "Engagement letter", "back": "An engagement letter documents the agreed-upon terms and respective responsibilities. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}, {"id": "ethics-f07", "sec": "ethics", "front": "Audit documentation", "back": "Documentation should show procedures performed, evidence obtained, and conclusions reached. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}, {"id": "ethics-f08", "sec": "ethics", "front": "Quality management", "back": "A quality management system addresses leadership, ethics, acceptance, performance, resources, information, and monitoring. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}, {"id": "ethics-f09", "sec": "ethics", "front": "Confidentiality", "back": "Confidentiality restricts client information disclosure except when authorized or required. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}, {"id": "ethics-f10", "sec": "ethics", "front": "Communication with governance", "back": "Significant findings and certain matters should be communicated to those charged with governance. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}, {"id": "risk-f01", "sec": "risk", "front": "Understanding the entity", "back": "Risk assessment starts with understanding the entity and its environment. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}, {"id": "risk-f02", "sec": "risk", "front": "Internal control", "back": "Understanding controls supports risk assessment and planning. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}, {"id": "risk-f03", "sec": "risk", "front": "Control environment", "back": "Tone at the top and management override concerns affect risk assessment. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}, {"id": "risk-f04", "sec": "risk", "front": "Fraud risk", "back": "Standards ordinarily presume fraud risk in revenue recognition. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}, {"id": "risk-f05", "sec": "risk", "front": "Materiality", "back": "Performance materiality reduces aggregation risk. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}, {"id": "risk-f06", "sec": "risk", "front": "Analytical procedures", "back": "Unexpected relationships can identify risks requiring further procedures. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}, {"id": "risk-f07", "sec": "risk", "front": "Significant risks", "back": "Significant risks involve matters requiring special audit consideration. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}, {"id": "risk-f08", "sec": "risk", "front": "Inherent risk", "back": "Complexity, judgment, and estimation uncertainty increase inherent risk. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}, {"id": "risk-f09", "sec": "risk", "front": "Control risk", "back": "Poorly designed or unimplemented controls increase control risk. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}, {"id": "risk-f10", "sec": "risk", "front": "Response to risk", "back": "Higher risk requires more persuasive evidence. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}, {"id": "evidence-f01", "sec": "evidence", "front": "Audit evidence reliability", "back": "External evidence received directly by the auditor is generally more reliable. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}, {"id": "evidence-f02", "sec": "evidence", "front": "Sufficiency and appropriateness", "back": "Evidence must be sufficient in quantity and appropriate in relevance/reliability. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}, {"id": "evidence-f03", "sec": "evidence", "front": "Inquiry", "back": "Inquiry is useful but generally requires corroboration. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}, {"id": "evidence-f04", "sec": "evidence", "front": "Recalculation", "back": "Recalculation independently checks arithmetic accuracy. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}, {"id": "evidence-f05", "sec": "evidence", "front": "Reperformance", "back": "Reperformance is strong evidence for control operation. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}, {"id": "evidence-f06", "sec": "evidence", "front": "Observation", "back": "Observation is limited to the point in time observed. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}, {"id": "evidence-f07", "sec": "evidence", "front": "Inspection", "back": "Inspection of documents can support rights, obligations, and terms. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}, {"id": "evidence-f08", "sec": "evidence", "front": "Confirmations", "back": "Confirmations are reliable when controlled by the auditor and received directly. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}, {"id": "evidence-f09", "sec": "evidence", "front": "Negative confirmations", "back": "Negative confirmations provide less persuasive evidence and require specific conditions. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}, {"id": "evidence-f10", "sec": "evidence", "front": "Sampling risk", "back": "Sampling risk arises because a sample is tested rather than the entire population. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}, {"id": "reporting-f01", "sec": "reporting", "front": "Unmodified opinion", "back": "An unmodified opinion is appropriate when statements are fairly presented. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}, {"id": "reporting-f02", "sec": "reporting", "front": "Qualified opinion", "back": "A material but not pervasive misstatement generally results in a qualified opinion. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}, {"id": "reporting-f03", "sec": "reporting", "front": "Adverse opinion", "back": "Material and pervasive misstatement results in an adverse opinion. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}, {"id": "reporting-f04", "sec": "reporting", "front": "Disclaimer of opinion", "back": "A pervasive inability to obtain evidence leads to a disclaimer. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}, {"id": "reporting-f05", "sec": "reporting", "front": "Emphasis-of-matter", "back": "Emphasis-of-matter highlights a properly presented or disclosed matter. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}, {"id": "reporting-f06", "sec": "reporting", "front": "Other-matter", "back": "Other-matter paragraphs address matters other than those in the statements/disclosures. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}, {"id": "reporting-f07", "sec": "reporting", "front": "Going concern", "back": "Adequate disclosure with substantial doubt usually leads to going-concern emphasis wording. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}, {"id": "reporting-f08", "sec": "reporting", "front": "Inadequate disclosure", "back": "Inadequate disclosure is a GAAP departure that can modify the opinion. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}, {"id": "reporting-f09", "sec": "reporting", "front": "Group audits", "back": "Group audits require planning, involvement, and appropriate reporting decisions. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}, {"id": "reporting-f10", "sec": "reporting", "front": "Comparative statements", "back": "Comparative reporting may require references to prior opinions or predecessor auditors. Exam tip: identify the rule, avoid the distractor, and connect the answer to evidence, documentation, communication, or reporting."}];
