function $(id){return document.getElementById(id)}
function load(){try{return JSON.parse(localStorage.getItem(STORAGE_KEY))||{}}catch(e){return {}}}
let state=load();
state.section=state.section||'ethics'; state.view=state.view||'dashboard'; state.scores=state.scores||{}; state.flash=state.flash||{}; state.sim=state.sim||{}; state.quizLimit=state.quizLimit||10; state.currentQuiz=state.currentQuiz||{}; state.currentSims=state.currentSims||{}; state.simLimit=state.simLimit||1; state.notes=state.notes||'';
function save(){localStorage.setItem(STORAGE_KEY,JSON.stringify(state))}
function shuffle(a){a=a.slice();for(let i=a.length-1;i>0;i--){let j=Math.floor(Math.random()*(i+1));[a[i],a[j]]=[a[j],a[i]]}return a}
function areaQs(sec=state.section){return QUESTIONS.filter(q=>q.sec===sec)}
function areaFlash(sec=state.section){return FLASH.filter(f=>f.sec===sec)}
function areaSims(sec=state.section){return SIMS.filter(s=>s.sec===sec)}
function setView(v){state.view=v;save();render()}
function setSection(sec){state.section=sec;save();render()}
function renderSections(){$('sections').innerHTML=SECTIONS.map(s=>`<button class="section ${state.section===s.id?'active':''}" onclick="setSection('${s.id}')">${s.name}</button>`).join('')}
function renderNav(){let names=[['dashboard','Dashboard'],['quiz','MCQs'],['sims','Simulations'],['flash','Flashcards'],['read','Readings'],['exam','Exam Mode'],['notes','Notes']];$('nav').innerHTML=names.map(n=>`<button class="${state.view===n[0]?'active':''}" onclick="setView('${n[0]}')">${n[1]}</button>`).join('')}
function readiness(sec){let qs=areaQs(sec), done=qs.filter(q=>state.scores[q.id]);let pct=done.length?Math.round(done.filter(q=>state.scores[q.id].correct).length/done.length*100):0;let fs=areaFlash(sec), mast=fs.filter(f=>state.flash[f.id]==='mastered').length;return Math.round(pct*.7+(mast/fs.length*100)*.3)}
function render(){renderSections();renderNav();({dashboard,quiz,sims,flash,read,exam,notes}[state.view]||dashboard)()}
function dashboard(){$('app').innerHTML=`<div class="grid">${SECTIONS.map(s=>`<div class="card"><b>${s.name}</b><div class="metric">${readiness(s.id)}%</div><div class="bar"><span style="width:${readiness(s.id)}%"></span></div><p class="muted">${areaQs(s.id).length} MCQs · ${areaSims(s.id).length} simulations · ${areaFlash(s.id).length} flashcards · Weight: ${s.weight}</p></div>`).join('')}</div><div class="card"><h2>v7.6 QA Notes</h2><p>No scenario labels. 80 MCQs per area. 10 simulations per area. Flashcards and exhibits are interactive. Sample-size controls are retained.</p></div>`}
function read(){let sec=SECTIONS.find(s=>s.id===state.section);$('app').innerHTML=`<div class="card"><h2>${sec.name}</h2><p>This section covers the selected AUD blueprint area. Use MCQs for rule recognition, simulations for exhibit-based application, and flashcards for recall.</p></div>`}
function quickSize(n){$('sample').value=n;startQuiz(true)}
function quiz(){let total=areaQs().length;let ids=state.currentQuiz[state.section]||[];$('app').innerHTML=`<div class="card"><h2>MCQ Setup</h2><p class="muted">${total} questions available in this area.</p><div class="actions"><button onclick="quickSize(10)">10</button><button onclick="quickSize(20)">20</button><button onclick="quickSize(30)">30</button><button onclick="quickSize(50)">50</button><button onclick="quickSize(${total})">All</button><label>Custom <input id="sample" type="number" min="1" max="${total}" value="${Math.min(state.quizLimit,total)}"></label><button class="primary" onclick="startQuiz(true)">Start New Quiz</button></div></div><div id="quizRun"></div>`; if(ids.length) renderQuizRun()}
function startQuiz(newSet){let total=areaQs().length;let n=Math.max(1,Math.min(Number($('sample').value||10),total));state.quizLimit=n;state.currentQuiz[state.section]=shuffle(areaQs()).slice(0,n).map(q=>q.id);save();renderQuizRun()}
function renderQuizRun(){let ids=state.currentQuiz[state.section]||[];let qs=ids.map(id=>QUESTIONS.find(q=>q.id===id)).filter(Boolean);$('quizRun').innerHTML=qs.map((q,i)=>`<div class="card"><p class="muted">Question ${i+1} of ${qs.length} · ${q.topic} · ${q.difficulty}</p><h3>${q.q}</h3>${q.choices.map((c,j)=>`<button class="choice" onclick="answer('${q.id}','${'ABCD'[j]}',this)">${'ABCD'[j]}. ${c}</button>`).join('')}<div id="fb-${q.id}"></div></div>`).join('')}
function answer(id,letter,btn){let q=QUESTIONS.find(x=>x.id===id);let correct=letter===q.ans;state.scores[id]={correct,letter,date:new Date().toISOString()};save();btn.classList.add(correct?'correct':'wrong');$(`fb-${id}`).innerHTML=`<p><b>${correct?'Correct.':'Incorrect.'}</b> Correct answer: ${q.ans}. ${q.exp}</p>`}
function quickSim(n){state.simLimit=n;startSims()}
function sims(){let total=areaSims().length;$('app').innerHTML=`<div class="card"><h2>Simulation Setup</h2><p class="muted">${total} CPA-style task-based simulations available in this area.</p><div class="actions"><button onclick="quickSim(1)">1 Simulation</button><button onclick="quickSim(2)">2 Simulations</button><button onclick="quickSim(3)">3 Simulations</button><label>Custom <input id="simSample" type="number" min="1" max="${total}" value="${Math.min(state.simLimit,total)}"></label><button class="primary" onclick="startSims()">Start Simulations</button></div></div><div id="simRun"></div>`; if((state.currentSims[state.section]||[]).length) renderSimRun()}
function startSims(){let total=areaSims().length;let el=$('simSample');let n=el?Number(el.value):state.simLimit;n=Math.max(1,Math.min(n||1,total));state.simLimit=n;state.currentSims[state.section]=shuffle(areaSims()).slice(0,n).map(s=>s.id);save();renderSimRun()}
function toggleExhibit(id){let el=$(id); if(el) el.classList.toggle('hide')}
function renderSimRun(){let ids=state.currentSims[state.section]||[];let list=ids.map(id=>SIMS.find(s=>s.id===id)).filter(Boolean);$('simRun').innerHTML=list.map((s,i)=>`<div class="card"><h2>Simulation ${i+1} of ${list.length}: ${s.title}</h2><span class="pill">${s.type}</span><h3>Exhibits</h3>${s.exhibits.map((e,j)=>`<button type="button" onclick="toggleExhibit('${s.id}-ex${j}')">Open ${e}</button><div id="${s.id}-ex${j}" class="card hide"><b>${e}</b><p>${s.exhibitBodies[j]}</p></div>`).join('')}<p><b>Task:</b> ${s.prompt}</p><ol>${s.tasks.map(t=>`<li>${t}</li>`).join('')}</ol><textarea id="simtxt-${s.id}">${state.sim[s.id]?.text||''}</textarea><h3>Self-check rubric</h3>${s.rubric.map((r,j)=>`<label><input type="checkbox"> ${r}</label><br>`).join('')}<button class="primary" onclick="saveSim('${s.id}')">Save Simulation</button><div id="saved-${s.id}"></div></div>`).join('')}
function saveSim(id){state.sim[id]={text:$(`simtxt-${id}`).value,date:new Date().toISOString()};save();$(`saved-${id}`).innerHTML='<p>Saved.</p>'}
function flash(){let fs=areaFlash();state.flashIndex=state.flashIndex||{};let idx=Math.min(state.flashIndex[state.section]||0,fs.length-1);let f=fs[idx];let back=state.flashBack==='1';$('app').innerHTML=`<div class="card"><h2>Flashcards</h2><p class="muted">Card ${idx+1} of ${fs.length}</p><div class="card"><h3>${back?'Answer / Exam Note':'Prompt'}</h3><p class="metric">${back?f.back:f.front}</p><p><span class="pill">Status: ${state.flash[f.id]||'new'}</span></p><div class="actions"><button onclick="flipFlash()">${back?'Show Prompt':'Flip Card'}</button><button onclick="markFlash('${f.id}','learning')">Learning</button><button class="primary" onclick="markFlash('${f.id}','mastered')">Mastered</button><button onclick="prevFlash()">Previous</button><button onclick="nextFlash()">Next</button></div></div></div>`}
function flipFlash(){state.flashBack=state.flashBack==='1'?'0':'1';save();flash()}
function nextFlash(){let fs=areaFlash();state.flashIndex=state.flashIndex||{};state.flashIndex[state.section]=Math.min((state.flashIndex[state.section]||0)+1,fs.length-1);state.flashBack='0';save();flash()}
function prevFlash(){state.flashIndex=state.flashIndex||{};state.flashIndex[state.section]=Math.max((state.flashIndex[state.section]||0)-1,0);state.flashBack='0';save();flash()}
function markFlash(id,val){state.flash[id]=val;save();flash()}
function exam(){$('app').innerHTML=`<div class="grid">${SECTIONS.map(s=>`<div class="card"><h3>${s.name}</h3><p>${areaQs(s.id).length} MCQs · ${areaSims(s.id).length} simulations</p><button class="primary" onclick="state.section='${s.id}';save();setView('quiz')">Start MCQs</button> <button onclick="state.section='${s.id}';save();setView('sims')">Start Simulations</button></div>`).join('')}</div>`}
function notes(){$('app').innerHTML=`<div class="card"><h2>Notes</h2><textarea id="notesBox">${state.notes}</textarea><br><button class="primary" onclick="state.notes=$('notesBox').value;save()">Save Notes</button></div>`}
if('serviceWorker' in navigator){navigator.serviceWorker.register('./sw.js').catch(()=>{})}
render();
